svg.script:
(function() {
  var svg        = document.getElementById('root');
  var chartArea  = document.getElementById('chart-area');
  var tip        = document.getElementById('tip');
  var tipPath    = document.getElementById('tip-path');
  var tipBdr     = document.getElementById('tip-bdr');
  var tipName    = document.getElementById('tip-name');
  var tipVal     = document.getElementById('tip-val');
  var tipPct     = document.getElementById('tip-pct');
  var TOTAL = 819293;
  var W = 96, H = 52, TH = 10;

  function bubPath(x, y, flip) {
    if (!flip) {
      return 'M'+(x-8)+','+y+' L'+(x-W/2+10)+','+y+' Q'+(x-W/2)+','+y+' '+(x-W/2)+','+(y-10)+
             ' L'+(x-W/2)+','+(y-H-TH)+' Q'+(x-W/2)+','+(y-H-TH-10)+' '+(x-W/2+10)+','+(y-H-TH-10)+
             ' L'+(x+W/2-10)+','+(y-H-TH-10)+' Q'+(x+W/2)+','+(y-H-TH-10)+' '+(x+W/2)+','+(y-H-TH)+
             ' L'+(x+W/2)+','+(y-10)+' Q'+(x+W/2)+','+y+' '+(x+W/2-10)+','+y+
             ' L'+(x+8)+','+y+' L'+x+','+(y+TH)+' Z';
    } else {
      return 'M'+(x-8)+','+y+' L'+(x-W/2+10)+','+y+' Q'+(x-W/2)+','+y+' '+(x-W/2)+','+(y+10)+
             ' L'+(x-W/2)+','+(y+H+TH)+' Q'+(x-W/2)+','+(y+H+TH+10)+' '+(x-W/2+10)+','+(y+H+TH+10)+
             ' L'+(x+W/2-10)+','+(y+H+TH+10)+' Q'+(x+W/2)+','+(y+H+TH+10)+' '+(x+W/2)+','+(y+H+TH)+
             ' L'+(x+W/2)+','+(y+10)+' Q'+(x+W/2)+','+y+' '+(x+W/2-10)+','+y+
             ' L'+(x+8)+','+y+' L'+x+','+(y-TH)+' Z';
    }
  }

  function showTip(evt, name, val) {
    var pt = svg.createSVGPoint();
    pt.x = evt.clientX; pt.y = evt.clientY;
    var sp = pt.matrixTransform(svg.getScreenCTM().inverse());
    var tx = Math.max(W/2+4, Math.min(sp.x, 1100-W/2-4));
    var ty = sp.y;
    var flip = ty < H + TH + 20;
    var p = bubPath(tx, ty, flip);
    tipPath.setAttribute('d', p); tipBdr.setAttribute('d', p);
    var textY = flip ? ty+TH+16 : ty-H-TH+16;
    tipName.setAttribute('x', tx); tipName.setAttribute('y', textY); tipName.textContent = name;
    tipVal.setAttribute('x', tx);  tipVal.setAttribute('y', textY+18); tipVal.textContent = val.toLocaleString()+' lines';
    tipPct.setAttribute('x', tx);  tipPct.setAttribute('y', textY+32); tipPct.textContent = (val/TOTAL*100).toFixed(1)+'% of total';
    tipName.setAttribute('text-anchor','middle');
    tipVal.setAttribute('text-anchor','middle');
    tipPct.setAttribute('text-anchor','middle');
    tip.style.opacity = '1';
  }

  var cells = svg.querySelectorAll('.icell');

  cells.forEach(function(c) {
    c.addEventListener('mouseenter', function(e) {
      chartArea.classList.add('dimming');
      c.classList.add('hovered');
      showTip(e, c.getAttribute('data-name'), parseInt(c.getAttribute('data-val')));
    });
    c.addEventListener('mousemove', function(e) {
      showTip(e, c.getAttribute('data-name'), parseInt(c.getAttribute('data-val')));
    });
    c.addEventListener('mouseleave', function() {
      chartArea.classList.remove('dimming');
      c.classList.remove('hovered');
      tip.style.opacity = '0';
    });
  });

  /* Staggered fade-in by depth level */
  [0,1,2,3,4].forEach(function(d) {
    svg.querySelectorAll('.d'+d).forEach(function(el, i) {
      el.style.opacity = '0';
      setTimeout(function() {
        el.style.transition = 'opacity 1.2s ease';
        el.style.opacity = '1';
      }, d * 350 + i * 10);
    });
  });

  function setMode(wantDark) {
    if (wantDark === svg.classList.contains('dark')) return;
    var thumb = document.getElementById('tthumb'), lbl = document.getElementById('tlabel');
    if (wantDark) { svg.classList.add('dark'); thumb.setAttribute('cx','52'); lbl.textContent='Light'; }
    else          { svg.classList.remove('dark'); thumb.setAttribute('cx','16'); lbl.textContent='Dark'; }
  }

  document.getElementById('dark-toggle').addEventListener('click', function() { setMode(!svg.classList.contains('dark')); });
  document.getElementById('print-toggle').addEventListener('click', function() {
    var thumb=document.getElementById('pthumb'), lbl=document.getElementById('plabel');
    if (svg.classList.toggle('print')) { thumb.setAttribute('cx','52'); lbl.textContent='Screen'; }
    else { thumb.setAttribute('cx','16'); lbl.textContent='Print'; }
  });

  window.setMode = setMode;
  window.addEventListener('message', function(e) { if (e.data && e.data.type==='setMode') setMode(e.data.dark); });
  setMode(window.location.href.indexOf('theme=dark') !== -1);
})();
